<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';vp3_require_admin_permission('licenses.view');$pageTitle='Licenses';require VP3_ROOT.'/includes/admin-header.php';$cid=(int)vp3_input('customer_id');$sql='SELECT l.*,c.name customer_name,p.name product_name FROM licenses l JOIN customers c ON c.id=l.customer_id JOIN products p ON p.id=l.product_id';$params=[];if($cid){$sql.=' WHERE l.customer_id=?';$params[]=$cid;}$sql.=' ORDER BY l.id DESC LIMIT 250';$s=vp3_db()->prepare($sql);$s->execute($params);$rows=$s->fetchAll();?><div class="hero-actions"><h1>Licenses</h1><a class="button small" href="license.php">Issue license</a></div><div class="table-wrap"><table class="table"><thead><tr><th>Customer</th><th>Product</th><th>Key</th><th>Edition</th><th>Status</th><th>Activations</th><th>Expires</th><th></th></tr></thead><tbody><?php foreach($rows as $x):?><tr><td><?=vp3_e($x['customer_name'])?></td><td><?=vp3_e($x['product_name'])?></td><td><?=vp3_e($x['license_key_prefix'])?>…<br><small><?=vp3_e($x['license_fingerprint'])?></small></td><td><?=vp3_e($x['edition'])?></td><td><span class="badge <?=vp3_e($x['status'])?>"><?=vp3_e($x['status'])?></span></td><td><?=(int)$x['activation_count']?> / <?=(int)$x['max_activations']?></td><td><?=vp3_e($x['expires_at']?:'Never')?></td><td><a href="license.php?id=<?=(int)$x['id']?>">Open</a></td></tr><?php endforeach;?></tbody></table></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>